     1→// ============================================================================
     2→// WebSocket Proxy Plugin
     3→// Bidirectional WebSocket proxy to AI proctoring service
     4→// ============================================================================
     5→
     6→import fp from 'fastify-plugin';
     7→import { FastifyInstance } from 'fastify';
     8→import { WebSocket, WebSocketServer } from 'ws';
     9→import crypto from 'crypto';
    10→import { WSHandler } from '../websocket/ws.handler';
    11→import { authenticateWS, canAccessAttempt } from '../websocket/ws.auth';
    12→import { createViolationService } from '../modules/violation/violation.service';
    13→import { SignatureService } from '../modules/security/signature.service';
    14→import { ReplayPreventionService } from '../modules/security/replay-prevention.service';
    15→import logger from '../config/logger';
    16→import type { ClientMessage, AIMessage } from '../websocket/ws.types';
    17→
    18→// Helper to generate UUID
    19→function uuidv4(): string {
    20→  return crypto.randomUUID();
    21→}
    22→
    23→// ============================================================================
    24→// Plugin Configuration
    25→// ============================================================================
    26→
    27→export interface WebSocketProxyOptions {
    28→  prefix?: string;
    29→  aiServiceUrl?: string;
    30→}
    31→
    32→// ============================================================================
    33→// WebSocket Proxy Plugin
    34→// ============================================================================
    35→
    36→export default fp<WebSocketProxyOptions>(async (fastify: FastifyInstance, options: WebSocketProxyOptions) => {
    37→  const {
    38→    prefix = '/ws',
    39→    aiServiceUrl = process.env.AI_SERVICE_URL || 'ws://localhost:8000/proctor'
    40→  } = options;
    41→
    42→  const handler = new WSHandler();
    43→  const violationService = createViolationService(fastify.pg as any);
    44→
    45→  // Get security services
    46→  // @ts-ignore
    47→  const signatureService: SignatureService = fastify.security?.signatureService;
    48→  // @ts-ignore
    49→  const replayPrevention: ReplayPreventionService = fastify.security?.replayPreventionService;
    50→
    51→  // ==========================================================================
    52→  // Event Handlers
    53→  // ==========================================================================
    54→
    55→  // Violation detected - store in database
    56→  handler.on('violation:detected', async ({ session, message }: { session: any; message: any }) => {
    57→    if (message.type !== 'violation' || !message.flag) {
    58→      return; // Only store actual violations
    59→    }
    60→
    61→    try {
    62→      await violationService.recordViolation(
    63→        {
    64→          attemptId: session.attemptId,
    65→          violationType: message.violations[0] || 'unknown',
    66→          severity: 'warning',
    67→          detail: message.message,
    68→          metadata: message.details,
    69→          sessionId: session.sessionId,
    70→          timestamp: message.timestamp
    71→        },
    72→        session.userId,
    73→        signatureService
    74→      );
    75→
    76→      // Broadcast to teacher dashboards
    77→      handler.broadcastViolation({
    78→        attemptId: session.attemptId,
    79→        violation: message
    80→      });
    81→    } catch (error) {
    82→      logger.error('Failed to record violation:', error);
    83→    }
    84→  });
    85→
    86→  // Client disconnected - close AI connection
    87→  handler.on('client:disconnected', async ({ session }: { session: any }) => {
    88→    try {
    89→      // Store session end time
    90→      await fastify.pg.query(
    91→        `UPDATE proctoring_sessions
    92→        SET session_end = NOW()
    93→        WHERE attempt_id = $1 AND session_end IS NULL`,
    94→        [session.attemptId]
    95→      );
    96→    } catch (error) {
    97→      logger.error('Failed to update session end time:', error);
    98→    }
    99→
   100→    // Close AI connection
   101→    if (session.aiConnection?.isConnected) {
   102→      try {
   103→        session.aiConnection.socket.close();
   104→      } catch (error) {
   105→        logger.error('Failed to close AI connection:', error);
   106→      }
   107→    }
   108→
   109→    // Clean up session
   110→    await handler.closeSession(session.sessionId);
   111→  });
   112→
   113→  // AI unavailable - notify client
   114→  handler.on('ai:unavailable', ({ session }: { session: any }) => {
   115→    handler.sendToClient(session.sessionId, {
   116→      type: 'error',
   117→      error: 'AI Service Unavailable',
   118→      message: 'Proctoring service is not connected. Frames are not being monitored.',
   119→      timestamp: Date.now()
   120→    });
   121→  });
   122→
   123→  // ==========================================================================
   124→  // Create WebSocket Server
   125→  // ==========================================================================
   126→
   127→  const wss = new WebSocketServer({ noServer: true });
   128→
   129→  // Handle HTTP upgrade to WebSocket
   130→  fastify.server.on('upgrade', async (request, socket, head) => {
   131→    const url = new URL(request.url || '', `http://${request.headers.host}`);
   132→
   133→    // Only handle WebSocket requests for our prefix
   134→    if (!url.pathname.startsWith(`${prefix}/proctor`)) {
   135→      return;
   136→    }
   137→
   138→    wss.handleUpgrade(request, socket as any, head, (ws) => {
   139→      wss.emit('connection', ws, request);
   140→    });
   141→  });
   142→
   143→  // ==========================================================================
   144→  // Handle Incoming WebSocket Connections
   145→  // ==========================================================================
   146→
   147→  wss.on('connection', async (ws, request) => {
   148→    try {
   149→      // Authenticate connection
   150→      const user = await authenticateWS(request as any);
   151→
   152→      // Get session parameters from query
   153→      const requestUrl = new URL(request.url || '', `http://${request.headers.host}`);
   154→      const attemptId = requestUrl.searchParams.get('attemptId') || undefined;
   155→      const sessionId = requestUrl.searchParams.get('sessionId') || undefined;
   156→
   157→      if (!attemptId) {
   158→        ws.close(1008, 'Missing attemptId parameter');
   159→        return;
   160→      }
   161→
   162→      const attemptIdNum = parseInt(attemptId, 10);
   163→
   164→      // Verify access
   165→      const canAccess = await canAccessAttempt(fastify.pg, user, attemptIdNum);
   166→
   167→      if (!canAccess) {
   168→        ws.close(1008, 'Access denied');
   169→        return;
   170→      }
   171→
   172→      // Get exam info
   173→      const examResult = await fastify.pg.query(
   174→        `SELECT e.id as exam_id, ea.id as attempt_id, ea.status
   175→        FROM exam_attempts ea
   176→        JOIN exams e ON ea.exam_id = e.id
   177→        WHERE ea.id = $1`,
   178→        [attemptIdNum]
   179→      );
   180→
   181→      if (examResult.rows.length === 0) {
   182→        ws.close(1008, 'Attempt not found');
   183→        return;
   184→      }
   185→
   186→      const attempt = examResult.rows[0];
   187→
   188→      if (attempt.status !== 'in_progress') {
   189→        ws.close(1008, 'Attempt is not in progress');
   190→        return;
   191→      }
   192→
   193→      // Generate session ID if not provided
   194→      const finalSessionId = sessionId || uuidv4();
   195→
   196→      // Create or get session
   197→      let session = handler.getSession(finalSessionId);
   198→
   199→      if (!session) {
